Index: src/schema-header.mjs
===================================================================
--- src/schema-header.mjs	
+++ src/schema-header.mjs	
@@ -1,7 +1,21 @@
 export function parseSchemaHeader(line) {
-  return String(line)
-    .trim()
-    .split('|')
-    .map((field) => field.trim())
-    .filter(Boolean);
+  const fields = [];
+  let field = "";
+  let inQuotes = false;
+
+  for (const char of String(line)) {
+    if (char === '"') {
+      inQuotes = !inQuotes;
+    }
+
+    if (char === "|" && !inQuotes) {
+      fields.push(field.trim());
+      field = "";
+    } else {
+      field += char;
+    }
+  }
+
+  fields.push(field.trim());
+  return fields;
 }

